func newCmdAndroidAppIActivityManager_RegisterUidObserverForUids() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "register-uid-observer-for-uids",
		Short: "Call RegisterUidObserverForUids(observer IUidObserver, which int32, cutpoint int32, uids []int32) -> binder.IBinder",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := context.Background()

			conn, err := cliutil.OpenConn(ctx, cmd)
			if err != nil {
				return err
			}
			defer conn.Close(ctx)

			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.app.IActivityManager")
			}
			if err != nil {
				return err
			}

			svcProxy := app.NewActivityManagerProxy(svc)

			flagObserverName, err := cmd.Flags().GetString("observer")
			if err != nil {
				return fmt.Errorf("reading flag observer: %w", err)
			}
			flagObserverBinder, err := conn.GetService(ctx, flagObserverName)
			if err != nil {
				return fmt.Errorf("resolving service %q for observer: %w", flagObserverName, err)
			}
			var flagObserver app.IUidObserver = app.NewUidObserverProxy(flagObserverBinder)

			flagWhich, err := cmd.Flags().GetInt32("which")
			if err != nil {
				return fmt.Errorf("reading flag which: %w", err)
			}

			flagCutpoint, err := cmd.Flags().GetInt32("cutpoint")
			if err != nil {
				return fmt.Errorf("reading flag cutpoint: %w", err)
			}

			flagUidsStr, err := cmd.Flags().GetString("uids")
			if err != nil {
				return fmt.Errorf("reading flag uids: %w", err)
			}
			var flagUids []int32
			if flagUidsStr != "" {
				for _, _s := range strings.Split(flagUidsStr, ",") {
					_v, _err := strconv.ParseInt(strings.TrimSpace(_s), 0, 32)
					if _err != nil {
						return fmt.Errorf("invalid int32 in uids: %w", _err)
					}
					flagUids = append(flagUids, int32(_v))
				}
			}

			result, err := svcProxy.RegisterUidObserverForUids(ctx, flagObserver, flagWhich, flagCutpoint, flagUids)
			if err != nil {
				return err
			}

			mode, _ := cmd.Root().PersistentFlags().GetString("format")
			f := cliutil.NewFormatter(mode, os.Stdout)
			f.Value("result", result)
			return nil
		},
	}

	cmd.Flags().String("service-name", "", "ServiceManager name to use instead of descriptor discovery")
	cmd.Flags().String("observer", "", "observer (service name for IUidObserver)")
	_ = cmd.MarkFlagRequired("observer")
	cmd.Flags().Int32("which", 0, "which (int32)")
	_ = cmd.MarkFlagRequired("which")
	cmd.Flags().Int32("cutpoint", 0, "cutpoint (int32)")
	_ = cmd.MarkFlagRequired("cutpoint")
	cmd.Flags().String("uids", "", "uids (comma-separated int32)")
	_ = cmd.MarkFlagRequired("uids")

	return cmd
}

