			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.app.IActivityManager")
			}
			if err != nil {
				return err
			}

			svcProxy := app.NewActivityManagerProxy(svc)

			flagPidsStr, err := cmd.Flags().GetString("pids")
			if err != nil {
				return fmt.Errorf("reading flag pids: %w", err)
			}
			var flagPids []int32
			if flagPidsStr != "" {
				for _, _s := range strings.Split(flagPidsStr, ",") {
					_v, _err := strconv.ParseInt(strings.TrimSpace(_s), 0, 32)
					if _err != nil {
						return fmt.Errorf("invalid int32 in pids: %w", _err)
					}
					flagPids = append(flagPids, int32(_v))
				}
			}

			result, err := svcProxy.GetProcessPss(ctx, flagPids)
			if err != nil {
				return err
			}

