func newCmdAndroidAppIEphemeralResolver_GetEphemeralResolveInfoList() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "get-ephemeral-resolve-info-list",
		Short: "Call GetEphemeralResolveInfoList(callback IRemoteCallback, digestPrefix []int32, sequence int32)",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := context.Background()

			conn, err := cliutil.OpenConn(ctx, cmd)
			if err != nil {
				return err
			}
			defer conn.Close(ctx)

			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.app.IEphemeralResolver")
			}
			if err != nil {
				return err
			}

			svcProxy := app.NewEphemeralResolverProxy(svc)

			flagCallbackName, err := cmd.Flags().GetString("callback")
			if err != nil {
				return fmt.Errorf("reading flag callback: %w", err)
			}
			flagCallbackBinder, err := conn.GetService(ctx, flagCallbackName)
			if err != nil {
				return fmt.Errorf("resolving service %q for callback: %w", flagCallbackName, err)
			}
			var flagCallback os2.IRemoteCallback = os2.NewRemoteCallbackProxy(flagCallbackBinder)

			flagDigestPrefixStr, err := cmd.Flags().GetString("digestPrefix")
			if err != nil {
				return fmt.Errorf("reading flag digestPrefix: %w", err)
			}
			var flagDigestPrefix []int32
			if flagDigestPrefixStr != "" {
				for _, _s := range strings.Split(flagDigestPrefixStr, ",") {
					_v, _err := strconv.ParseInt(strings.TrimSpace(_s), 0, 32)
					if _err != nil {
						return fmt.Errorf("invalid int32 in digestPrefix: %w", _err)
					}
					flagDigestPrefix = append(flagDigestPrefix, int32(_v))
				}
			}

			flagSequence, err := cmd.Flags().GetInt32("sequence")
			if err != nil {
				return fmt.Errorf("reading flag sequence: %w", err)
			}

			err = svcProxy.GetEphemeralResolveInfoList(ctx, flagCallback, flagDigestPrefix, flagSequence)
			if err != nil {
				return err
			}

			mode, _ := cmd.Root().PersistentFlags().GetString("format")
			f := cliutil.NewFormatter(mode, os.Stdout)
			f.Value("status", "ok")
			return nil
		},
	}

	cmd.Flags().String("service-name", "", "ServiceManager name to use instead of descriptor discovery")
	cmd.Flags().String("callback", "", "callback (service name for IRemoteCallback)")
	_ = cmd.MarkFlagRequired("callback")
	cmd.Flags().String("digestPrefix", "", "digestPrefix (comma-separated int32)")
	_ = cmd.MarkFlagRequired("digestPrefix")
	cmd.Flags().Int32("sequence", 0, "sequence (int32)")
	_ = cmd.MarkFlagRequired("sequence")

	return cmd
}

