func newCmdAndroidAppIWallpaperManager_SetWallpaper() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "set-wallpaper",
		Short: "Call SetWallpaper(name string, screenOrientations []int32, crops []Rect, allowBackup bool, extras Bundle, which int32, completion IWallpaperManagerCallback) -> int32",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := context.Background()

			conn, err := cliutil.OpenConn(ctx, cmd)
			if err != nil {
				return err
			}
			defer conn.Close(ctx)

			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.app.IWallpaperManager")
			}
			if err != nil {
				return err
			}

			svcProxy := app.NewWallpaperManagerProxy(svc)

			flagName, err := cmd.Flags().GetString("name")
			if err != nil {
				return fmt.Errorf("reading flag name: %w", err)
			}

			flagScreenOrientationsStr, err := cmd.Flags().GetString("screenOrientations")
			if err != nil {
				return fmt.Errorf("reading flag screenOrientations: %w", err)
			}
			var flagScreenOrientations []int32
			if flagScreenOrientationsStr != "" {
				for _, _s := range strings.Split(flagScreenOrientationsStr, ",") {
					_v, _err := strconv.ParseInt(strings.TrimSpace(_s), 0, 32)
					if _err != nil {
						return fmt.Errorf("invalid int32 in screenOrientations: %w", _err)
					}
					flagScreenOrientations = append(flagScreenOrientations, int32(_v))
				}
			}

			flagCropsJSON, err := cmd.Flags().GetString("crops")
			if err != nil {
				return fmt.Errorf("reading flag crops: %w", err)
			}
			var flagCrops []graphics.Rect
			if flagCropsJSON != "" {
				if err := json.Unmarshal([]byte(flagCropsJSON), &flagCrops); err != nil {
					return fmt.Errorf("invalid JSON for crops: %w", err)
				}
			}

			flagAllowBackup, err := cmd.Flags().GetBool("allowBackup")
			if err != nil {
				return fmt.Errorf("reading flag allowBackup: %w", err)
			}

			var flagExtras os2.Bundle
			flagWhich, err := cmd.Flags().GetInt32("which")
			if err != nil {
				return fmt.Errorf("reading flag which: %w", err)
			}

			flagCompletionName, err := cmd.Flags().GetString("completion")
			if err != nil {
				return fmt.Errorf("reading flag completion: %w", err)
			}
			flagCompletionBinder, err := conn.GetService(ctx, flagCompletionName)
			if err != nil {
				return fmt.Errorf("resolving service %q for completion: %w", flagCompletionName, err)
			}
			var flagCompletion app.IWallpaperManagerCallback = app.NewWallpaperManagerCallbackProxy(flagCompletionBinder)

			result, err := svcProxy.SetWallpaper(ctx, flagName, flagScreenOrientations, flagCrops, flagAllowBackup, flagExtras, flagWhich, flagCompletion)
			if err != nil {
				return err
			}

			mode, _ := cmd.Root().PersistentFlags().GetString("format")
			f := cliutil.NewFormatter(mode, os.Stdout)
			f.Value("result", result)
			return nil
		},
	}

	cmd.Flags().String("service-name", "", "ServiceManager name to use instead of descriptor discovery")
	cmd.Flags().String("name", "", "name (string)")
	_ = cmd.MarkFlagRequired("name")
	cmd.Flags().String("screenOrientations", "", "screenOrientations (comma-separated int32)")
	_ = cmd.MarkFlagRequired("screenOrientations")
	cmd.Flags().String("crops", "", "crops (JSON []Rect)")
	_ = cmd.MarkFlagRequired("crops")
	cmd.Flags().Bool("allowBackup", false, "allowBackup (bool)")
	_ = cmd.MarkFlagRequired("allowBackup")
	cmd.Flags().Int32("which", 0, "which (int32)")
	_ = cmd.MarkFlagRequired("which")
	cmd.Flags().String("completion", "", "completion (service name for IWallpaperManagerCallback)")
	_ = cmd.MarkFlagRequired("completion")

	return cmd
}

